import Home from './Home.vue'
import Layout from './Layout.vue'
const router = createRouter({ 
  history: createWebHashHistory(),//路由模式
  routes: [  
         //一个个的路由规则
    {
       path: '/',
       component: Layout,
       name: 'Layout'  //命名路由
    },
    {
      path: '/home',
      component: Home,
      name: 'Home'  //命名路由
    }
     ]
 })
export default router
